from docx.oxml.ns import qn
from docx.oxml import OxmlElement

OUTPUT = os.path.expanduser(r"~/Downloads/学习/生物统计/生物统计课件整理.docx")
TMP = os.path.expanduser(r"~/AppData/Local/Temp/biostat_v3_tmp.docx")

# === Unicode math constants ===
SUM  = '\u2211'
SQRT = '\u221a'
MU   = '\u03bc'
SIGMA = '\u03c3'
SQ   = '\u00b2'
PI   = '\u03c0'
CHI  = '\u03c7'
ALPHA = '\u03b1'
BETA  = '\u03b2'
X_BAR = 'x\u0304'
Y_BAR = 'y\u0304'

def sf(r, cn='宋体', en='Times New Roman', sz=Pt(10.5)):
    r.font.size=sz; r.font.name=en; r.font.bold=False; r.font.italic=False
    r.font.color.rgb=RGBColor(0,0,0)
    r.element.rPr.rFonts.set(qn('w:eastAsia'),cn)

def hd(doc,text,level=2):
    sz={2:Pt(14),3:Pt(12),4:Pt(12)}[level]
    p=doc.add_paragraph(); p.style=doc.styles[f'Heading {level}']
    r=p.add_run(text)
    r.font.bold=False; r.font.italic=False; r.font.size=sz
    r.font.name='Times New Roman'; r.font.color.rgb=RGBColor(0,0,0)
    r.element.rPr.rFonts.set(qn('w:eastAsia'),'黑体')
    p.paragraph_format.first_line_indent=None; p.paragraph_format.left_indent=None
    p.paragraph_format.space_before=Pt(6 if level>=3 else 10)
    p.paragraph_format.space_after=Pt(3)

def bd(doc,text):
    p=doc.add_paragraph(); r=p.add_run(text); sf(r)
    p.paragraph_format.line_spacing=1.2; p.paragraph_format.space_after=Pt(1)
    p.paragraph_format.first_line_indent=Pt(21)

def ct(doc,text):
    p=doc.add_paragraph(); p.alignment=1; r=p.add_run(text); sf(r)
    p.paragraph_format.space_after=Pt(2)

def tb3(doc,hds,rows,cap=None):
    if cap: ct(doc,cap)
    t=doc.add_table(rows=1+len(rows),cols=len(hds))
    for i,h in enumerate(hds):
        c=t.rows[0].cells[i]; c.text=''
        r=c.paragraphs[0].add_run(h); sf(r,sz=Pt(10))
        c.paragraphs[0].alignment=1
    for ri,rd in enumerate(rows):
        for ci,v in enumerate(rd):
            c=t.rows[ri+1].cells[ci]; c.text=''
            r=c.paragraphs[0].add_run(str(v)); sf(r,sz=Pt(9))
            c.paragraphs[0].alignment=1
    tb=OxmlElement('w:tblBorders')
    for s in ['top','left','bottom','right','insideH','insideV']:
        e=OxmlElement(f'w:{s}'); e.set(qn('w:val'),'nil'); tb.append(e)
    t._tbl.tblPr.append(tb)
    for ri,row in enumerate(t.rows):
        for cell in row.cells:
            tc=cell._tc.get_or_add_tcPr()
            old=tc.find(qn('w:tcBorders'))
            if old is not None: tc.remove(old)
            b=OxmlElement('w:tcBorders')
            if ri==0:
                tp=OxmlElement('w:top');tp.set(qn('w:val'),'single');tp.set(qn('w:sz'),'12');b.append(tp)
                bm=OxmlElement('w:bottom');bm.set(qn('w:val'),'single');bm.set(qn('w:sz'),'6');b.append(bm)
            if ri==len(t.rows)-1:
                bm=OxmlElement('w:bottom');bm.set(qn('w:val'),'single');bm.set(qn('w:sz'),'12');b.append(bm)
            tc.append(b)
    g=t._tbl.find(qn('w:tblGrid'))
    if g is not None:
        for gc in g.findall(qn('w:gridCol')):
            if gc.get(qn('w:w')) is not None: gc.attrib.pop(qn('w:w'))
    for row in t._tbl.findall(qn('w:tr')):
        for cell in row.findall(qn('w:tc')):
            tp=cell.find(qn('w:tcPr'))
            if tp is not None:
                tw=tp.find(qn('w:tcW'))
                if tw is not None: tp.remove(tw)
    t.autofit=True
    ow=t._tbl.tblPr.find(qn('w:tblW'))
    if ow is not None: t._tbl.tblPr.remove(ow)
    tw=OxmlElement('w:tblW');tw.set(qn('w:w'),'5000');tw.set(qn('w:type'),'pct')
    t._tbl.tblPr.append(tw)
    for row in t.rows:
        for cell in row.cells:
            for p in cell.paragraphs: p.paragraph_format.first_line_indent=Pt(0)
    for row in t._tbl.findall(qn('w:tr')):
        tp=row.find(qn('w:trPr'))
        if tp is None:tp=OxmlElement('w:trPr');row.insert(0,tp)
        oc=tp.find(qn('w:cantSplit'))
        if oc is not None: tp.remove(oc)
        cs=OxmlElement('w:cantSplit');cs.set(qn('w:val'),'1');tp.append(cs)

def qq(doc,text):
    p=doc.add_paragraph();r=p.add_run(text);sf(r)
    p.paragraph_format.first_line_indent=None;p.paragraph_format.left_indent=None
    p.paragraph_format.space_before=Pt(6);p.paragraph_format.space_after=Pt(1)

def qa(doc,text=None):
    p=doc.add_paragraph()
    r=p.add_run(f'答案: {text}' if text else '答案:');sf(r)
    p.paragraph_format.first_line_indent=Pt(21);p.paragraph_format.space_after=Pt(1)

def qp(doc,text):
    p=doc.add_paragraph();r=p.add_run(text);sf(r)
    p.paragraph_format.left_indent=Pt(42);p.paragraph_format.first_line_indent=Pt(-10.5)
    p.paragraph_format.space_after=Pt(0)

def qe(doc,text):
    p=doc.add_paragraph()
    r=p.add_run('\u89e3\u6790: '+text);sf(r,sz=Pt(10))
    p.paragraph_format.first_line_indent=Pt(21)
    p.paragraph_format.space_before=Pt(2);p.paragraph_format.space_after=Pt(4)


