def main():
    os.makedirs(os.path.dirname(OUTPUT), exist_ok=True)
    doc = Document()
    st = doc.styles['Normal']
    st.font.name = 'Times New Roman'
    st.element.rPr.rFonts.set(qn('w:eastAsia'), '宋体')
    st.font.size = Pt(10.5)
    st.font.bold = False
    st.font.italic = False

    p = doc.add_paragraph(); p.alignment = 1
    r = p.add_run('水产生物统计 课件复习资料')
    sf(r, cn='黑体', sz=Pt(16))
    p.paragraph_format.space_after = Pt(12)

    p = doc.add_paragraph(); p.alignment = 1
    r = p.add_run('华中农业大学水产学院')
    sf(r, sz=Pt(12))

    bd(doc, '本资料根据课程PPT内容整理, 涵盖各章核心知识点, 公式和典型例题, 供复习参考.')
    doc.add_page_break()
    ch0(doc)
    doc.add_page_break()
    ch1(doc)
    doc.add_page_break()
    ch2(doc)
    doc.add_page_break()
    ch3(doc)
    doc.add_page_break()
    ch4(doc)
    doc.add_page_break()
    ch5(doc)
    doc.add_page_break()
    ch6(doc)
    doc.add_page_break()
    appendix(doc)

    doc.save(TMP)
    import shutil
    shutil.copy2(TMP, OUTPUT)
    os.remove(TMP)
    chars = sum(len(p.text) for p in doc.paragraphs)
    print(f'OK: {OUTPUT}')
    print(f'    paragraphs: {len(doc.paragraphs)}, tables: {len(doc.tables)}, chars: {chars}')

if __name__ == '__main__':
    main()
